/**
 * DNN forward pass.
 * obs:    input array  [6]
 * output: output array [2]
 *
 * Note: clamp output to [-1, 1] before sending to motor driver.
 */
static inline void actor_forward(const float* obs, float* output) {
    float buf0[48];
    float buf1[48];
    const float* in  = obs;
    float*       out = buf0;

    // Layer 0: 6 -> 48, activation=tanh
    for (int o = 0; o < 48; o++) {
        float acc = layer0_bias[o];
        for (int j = 0; j < 6; j++)
            acc += layer0_weight[o * 6 + j] * in[j];
        out[o] = tanhf(acc);
    }
    in  = out;
    out = (out == buf0) ? buf1 : buf0;

    // Layer 1: 48 -> 48, activation=tanh
    for (int o = 0; o < 48; o++) {
        float acc = layer1_bias[o];
        for (int j = 0; j < 48; j++)
            acc += layer1_weight[o * 48 + j] * in[j];
        out[o] = tanhf(acc);
    }
    in  = out;
    out = (out == buf0) ? buf1 : buf0;

    // Layer 2: 48 -> 2, activation=none (output layer)
    for (int o = 0; o < 2; o++) {
        float acc = layer2_bias[o];
        for (int j = 0; j < 48; j++)
            acc += layer2_weight[o * 48 + j] * in[j];
        out[o] = acc;
    }
    for (int o = 0; o < 2; o++)
        output[o] = out[o];

}